#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use Storable qw(nstore retrieve);
use File::Spec;
use File::Basename;
use File::Path qw(make_path);
use Digest::MD5 qw(md5_hex);
use Time::HiRes qw(time);

my $cgi = CGI->new;

# Retrieve session ID from cookies
my $session_id = $cgi->cookie('session_id');

# If session ID does not exist, generate a new one
unless ($session_id) {
    # Generate a unique session id using time and process id
    my $unique = time() . $$ . {} . rand();
    $session_id = md5_hex($unique);
