# Define the session file path
my $session_dir = "/tmp";
my $session_file = File::Spec->catfile($session_dir, "sess_$session_id");

# Ensure session directory exists (in case it's not there, though /tmp usually exists)
unless (-d $session_dir) {
    make_path($session_dir);
}

# Attempt to load session data if file exists, otherwise initialize it
my $session_data = {};
if (-e $session_file) {
    eval {
        $session_data = retrieve($session_file);
        1;
    } or do {
        # If retrieval fails, start with an empty session
        $session_data = {};
